#include<bits/stdc++.h>
#define int long long
using namespace std;
signed main(){
	int n, y, s, t;
	cin >> n >> y >> s >> t;
	for(int i = 1; i <= n; i++){
		if(y <= (i - 1) * s && ((i - 1) * s - y ) % t == 0) continue;
		if(y <= i * s && (i * s - y) % t == 0) continue;
		cout << "Yes";
		return 0;
	}
	cout << "No";
    return 0;
}
